#[test]
fn stress_continuation_timeout_under_load() {
    init_test_logging();

    let config = ConnectionConfig {
        continuation_timeout: Duration::from_millis(100), // Fast for testing
        max_concurrent_streams: 1000,
    };

    let (mut server, mut clients) = create_test_harness(config);
    let mut stalled_count = 0;
    let mut completed_count = 0;

    for i in 0..1000 {
        let client = &mut clients[i % 10];

        if i % 3 == 0 {
            // Stall: send HEADERS without END_HEADERS, never continue
            client.send_headers_incomplete(i as u32);
            stalled_count += 1;
        } else {
            // Complete: full header sequence
            client.send_headers_complete(i as u32);
            completed_count += 1;
        }
    }

    // Wait for timeouts
    std::thread::sleep(Duration::from_millis(200));

    // Verify server recovered from stalled connections
    let stats = server.connection_stats();
    assert_eq!(stats.active_continuation_states, 0, "all timeouts should fire");
    assert!(stats.timeout_errors >= stalled_count, "each stall should timeout");
    assert!(stats.successful_requests >= completed_count - 10, "most requests complete");

    // Verify connection pool health
    for client in &clients {
        assert!(client.can_send_new_request(), "clients should recover");
    }
}

#[test]
fn stress_continuation_rapid_timeout_cycle() {
    // Rapidly cycle through timeout states to detect memory leaks
    for cycle in 0..100 {
        let conn = create_connection();
        for stream in 0..100 {
            conn.start_continuation(stream);
            // Don't complete, let timeout fire
        }
        std::thread::sleep(Duration::from_millis(110));
        assert_eq!(conn.pending_continuations(), 0);
        drop(conn); // Verify clean drop
    }
    // No panic, no memory growth = pass
}
