fn process_frame(&mut self, frame: Frame) -> Result<...> {
    // Check continuation timeout
    if let Some(deadline) = self.continuation_deadline {
        if Instant::now() > deadline {
            self.continuation_stream_id = None;
            self.continuation_deadline = None;
            return Err(H2Error::protocol("CONTINUATION timeout"));
        }
    }

    // When starting continuation sequence:
    if !frame.flags.contains(END_HEADERS) {
        self.continuation_stream_id = Some(stream_id);
        self.continuation_deadline = Some(Instant::now() + CONTINUATION_TIMEOUT);
    }
    // ...
}
